// Build Postiz /public/v1/posts payload from a normalized input.
// Expected input on $json:
// {
//   posts: [
//     {
//       channelId: string,         // Postiz integration UUID
//       provider: 'instagram'|'tiktok'|'youtube'|'x'|'linkedin'|'bluesky'|'threads'|'mastodon'|'reddit'|'pinterest'|'medium'|'devto'|'hashnode'|'telegram'|'discord',
//       content: string,
//       mediaUrls?: string[],      // already-uploaded media URLs (Postiz fetches them)
//       settings?: object          // provider-specific settings overrides
//     }, ...
//   ],
//   scheduleAt?: string            // ISO timestamp; if omitted -> 'now'
// }

const input = $json;
if (!input.posts || !input.posts.length) {
  throw new Error('postiz_publish: posts[] is required');
}

const defaultSettings = {
  instagram:  { __type: 'instagram',  post_type: 'reel' },
  tiktok:     { __type: 'tiktok',     privacy_level: 'PUBLIC_TO_EVERYONE', autoAddMusic: true, content_posting_method: 'DIRECT_POST' },
  youtube:    { __type: 'youtube',    type: 'short', selfDeclaredMadeForKids: false },
  x:          { __type: 'x',          who_can_reply_post: 'everyone' },
  linkedin:   { __type: 'linkedin' },
  bluesky:    { __type: 'bluesky' },
  threads:    { __type: 'threads' },
  mastodon:   { __type: 'mastodon' },
  reddit:     { __type: 'reddit',     subreddit: [] },
  pinterest:  { __type: 'pinterest' },
  medium:     { __type: 'medium' },
  devto:      { __type: 'devto' },
  hashnode:   { __type: 'hashnode' },
  telegram:   { __type: 'telegram' },
  discord:    { __type: 'discord' }
};

const posts = input.posts.map((p) => {
  const base = defaultSettings[p.provider] || { __type: p.provider };
  const settings = { ...base, ...(p.settings || {}) };
  const image = (p.mediaUrls || []).map((u, i) => ({ id: `media-${i}`, path: u }));
  return {
    integration: { id: p.channelId },
    value: [
      {
        content: p.content,
        image
      }
    ],
    settings
  };
});

const payload = {
  type: input.scheduleAt ? 'schedule' : 'now',
  date: input.scheduleAt || new Date().toISOString(),
  shortLink: false,
  tags: input.tags || [],
  posts
};

return [{ json: payload }];
